1	import type { Metadata } from "next";
2	import "./globals.css";
3	
4	export const metadata: Metadata = {
5	  title: "Theseus — Founder Portal",
6	  description: "Upload ideas, track methodology, build the communal brain.",
7	};
8	
9	export default function RootLayout({
10	  children,
11	}: {
12	  children: React.ReactNode;
13	}) {
14	  return (
15	    <html lang="en" data-theme="dark" suppressHydrationWarning>
16	      <head>
17	        <script
18	          dangerouslySetInnerHTML={{
19	            __html: `
20	              try {
21	                const t = localStorage.getItem("theme");
22	                if (t) document.documentElement.setAttribute("data-theme", t);
23	              } catch {}
24	            `,
25	          }}
26	        />
27	      </head>
28	      <body>{children}</body>
29	    </html>
30	  );
31	}
