1	"use client";
2	
3	import { useState, useRef, useCallback } from "react";
4	import { useRouter } from "next/navigation";
5	
6	const ACCEPTED_EXTENSIONS = ".txt,.md,.markdown,.pdf,.docx,.vtt,.jsonl,.mp3,.m4a,.wav,.webm,.ogg";
7	
8	export default function UploadForm() {
9	  const router = useRouter();
10	  const fileRef = useRef<HTMLInputElement>(null);
11	  const [dragover, setDragover] = useState(false);
12	  const [file, setFile] = useState<File | null>(null);
13	  const [title, setTitle] = useState("");
14	  const [description, setDescription] = useState("");
15	  const [sourceType, setSourceType] = useState("written");
16	  const [uploading, setUploading] = useState(false);
17	  const [error, setError] = useState("");
18	  const [success, setSuccess] = useState("");
19	  const [pollLog, setPollLog] = useState("");
20	
21	  const handleFile = useCallback(
22	    (f: File) => {
23	      setFile(f);
24	      if (!title) {
25	        setTitle(f.name.replace(/\.[^/.]+$/, "").replace(/[-_]/g, " "));
26	      }
27	      if (f.type.startsWith("audio/")) {
28	        setSourceType("audio");
29	      }
30	    },
31	    [title],
32	  );
33	
34	  const handleDrop = useCallback(
35	    (e: React.DragEvent) => {
36	      e.preventDefault();
37	      setDragover(false);
38	      if (e.dataTransfer.files.length > 0) {
39	        handleFile(e.dataTransfer.files[0]);
40	      }
41	    },
42	    [handleFile],
43	  );
44	
45	  async function handleSubmit(e: React.FormEvent) {
46	    e.preventDefault();
47	    if (!file) {
48	      setError("Please select a file to upload");
49	      return;
50	    }
51	    setError("");
52	    setSuccess("");
53	    setUploading(true);
54	    setPollLog("");
55	
56	    const formData = new FormData();
57	    formData.append("file", file);
58	    formData.append("title", title);
59	    formData.append("description", description);
60	    formData.append("sourceType", sourceType);
61	
62	    const res = await fetch("/api/upload", {
63	      method: "POST",
64	      body: formData,
65	    });
66	
67	    const data = await res.json();
68	    if (!res.ok) {
69	      setUploading(false);
70	      setError(data.error || "Upload failed");
71	      return;
72	    }
73	
74	    setSuccess("Upload received. Processing…");
75	    const id = data.id as string;
76	
77	    const iv = setInterval(async () => {
78	      const pr = await fetch(`/api/upload/${id}`);
79	      const u = await pr.json();
80	      if (u.processLog) setPollLog(u.processLog.slice(-4000));
81	      if (u.status === "ingested" || u.status === "failed") {
82	        clearInterval(iv);
83	        setUploading(false);
84	        setSuccess(u.status === "ingested" ? "Ingest complete." : `Failed: ${u.errorMessage || ""}`);
85	        setTimeout(() => router.push("/dashboard"), 1800);
86	      }
87	    }, 1200);
88	
89	    setTimeout(() => clearInterval(iv), 600_000);
90	  }
91	
92	  return (
93	    <main style={{ maxWidth: "700px", margin: "0 auto", padding: "3rem 2rem" }}>
94	      <h1
95	        style={{
96	          fontFamily: "'Cinzel', serif",
97	          fontSize: "1.3rem",
98	          letterSpacing: "0.1em",
99	          color: "var(--gold)",
100	          marginBottom: "0.5rem",
101	        }}
102	      >
103	        Upload Contribution
104	      </h1>
105	      <p
106	        style={{
107	          fontFamily: "'EB Garamond', serif",
108	          fontSize: "1rem",
109	          color: "var(--parchment-dim)",
110	          marginBottom: "2rem",
111	        }}
112	      >
113	        Accepted: Markdown, plain text, WebVTT, dialectic JSONL, PDF, DOCX, and common audio formats.
114	        Files are stored outside <code>public/</code> and piped through{" "}
115	        <code>python -m noosphere ingest</code> then <code>synthesize</code>.
116	      </p>
117	
118	      <form onSubmit={handleSubmit} style={{ display: "flex", flexDirection: "column", gap: "1.5rem" }}>
119	        <div
120	          className={`upload-zone ${dragover ? "dragover" : ""}`}
121	          onClick={() => fileRef.current?.click()}
122	          onDragOver={(e) => {
123	            e.preventDefault();
124	            setDragover(true);
125	          }}
126	          onDragLeave={() => setDragover(false)}
127	          onDrop={handleDrop}
128	        >
129	          <input
130	            ref={fileRef}
131	            type="file"
132	            accept={ACCEPTED_EXTENSIONS}
133	            style={{ display: "none" }}
134	            onChange={(e) => {
135	              if (e.target.files?.[0]) handleFile(e.target.files[0]);
136	            }}
137	          />
138	          {file ? (
139	            <div>
140	              <p style={{ fontFamily: "'EB Garamond', serif", fontSize: "1.1rem", color: "var(--gold)" }}>
141	                {file.name}
142	              </p>
143	              <p
144	                style={{
145	                  fontFamily: "'Inter', sans-serif",
146	                  fontSize: "0.75rem",
147	                  color: "var(--parchment-dim)",
148	                  marginTop: "0.3rem",
149	                }}
150	              >
151	                {(file.size / 1024).toFixed(0)} KB · {file.type || "unknown type"}
152	              </p>
153	            </div>
154	          ) : (
155	            <div>
156	              <p style={{ fontFamily: "'EB Garamond', serif", fontSize: "1.1rem", color: "var(--parchment-dim)" }}>
157	                Drop a file here, or click to browse
158	              </p>
159	            </div>
160	          )}
161	        </div>
162	
163	        <div>
164	          <label
165	            style={{
166	              fontFamily: "'Inter', sans-serif",
167	              fontSize: "0.7rem",
168	              letterSpacing: "0.1em",
169	              textTransform: "uppercase",
170	              color: "var(--parchment-dim)",
171	              display: "block",
172	              marginBottom: "0.4rem",
173	            }}
174	          >
175	            Title
176	          </label>
177	          <input type="text" value={title} onChange={(e) => setTitle(e.target.value)} required />
178	        </div>
179	
180	        <div>
181	          <label
182	            style={{
183	              fontFamily: "'Inter', sans-serif",
184	              fontSize: "0.7rem",
185	              letterSpacing: "0.1em",
186	              textTransform: "uppercase",
187	              color: "var(--parchment-dim)",
188	              display: "block",
189	              marginBottom: "0.4rem",
190	            }}
191	          >
192	            Description (optional)
193	          </label>
194	          <textarea
195	            value={description}
196	            onChange={(e) => setDescription(e.target.value)}
197	            rows={3}
198	          />
199	        </div>
200	
201	        <div>
202	          <label
203	            style={{
204	              fontFamily: "'Inter', sans-serif",
205	              fontSize: "0.7rem",
206	              letterSpacing: "0.1em",
207	              textTransform: "uppercase",
208	              color: "var(--parchment-dim)",
209	              display: "block",
210	              marginBottom: "0.4rem",
211	            }}
212	          >
213	            Type
214	          </label>
215	          <select value={sourceType} onChange={(e) => setSourceType(e.target.value)}>
216	            <option value="written">Written</option>
217	            <option value="annotation">Annotation</option>
218	            <option value="external">External</option>
219	            <option value="audio">Audio</option>
220	            <option value="transcript">Transcript</option>
221	          </select>
222	        </div>
223	
224	        {error && <p style={{ color: "var(--ember)", fontSize: "0.9rem" }}>{error}</p>}
225	        {success && <p style={{ color: "var(--success)", fontSize: "0.9rem" }}>{success}</p>}
226	
227	        {pollLog && (
228	          <pre
229	            style={{
230	              maxHeight: "200px",
231	              overflow: "auto",
232	              fontSize: "0.65rem",
233	              background: "#0d0d12",
234	              padding: "0.75rem",
235	              borderRadius: "6px",
236	              color: "#b8b8c8",
237	            }}
238	          >
239	            {pollLog}
240	          </pre>
241	        )}
242	
243	        <button type="submit" className="btn-solid btn" disabled={uploading || !file}>
244	          {uploading ? "Processing…" : "Upload & Ingest"}
245	        </button>
246	      </form>
247	    </main>
248	  );
249	}
250

1	import { redirect } from "next/navigation";
2	import { getFounder } from "@/lib/auth";
