4	
5	export default async function AuthedLayout({ children }: { children: React.ReactNode }) {
6	  const founder = await getFounder();
7	  if (!founder) {
8	    redirect("/login");
9	  }
10	
11	  return (
12	    <>
13	      <Nav
14	        founder={{
15	          name: founder.name,
16	          username: founder.username,
17	          organizationSlug: founder.organization.slug,
18	        }}
19	      />
20	      {children}
21	    </>
22	  );
23	}
