1	import Link from "next/link";
2	import { fetchVoicesFromNoosphere } from "@/lib/noosphereVoicesBridge";
3	
4	export default async function VoicesPage() {
5	  const { rows, skipped, message } = await fetchVoicesFromNoosphere();
6	
7	  return (
8	    <main style={{ maxWidth: "960px", margin: "0 auto", padding: "3rem 2rem" }}>
9	      <h1
10	        style={{
11	          fontFamily: "'Cinzel', serif",
12	          color: "var(--gold)",
13	          letterSpacing: "0.08em",
14	        }}
15	      >
16	        Voices
17	      </h1>
18	      <p style={{ color: "var(--parchment-dim)", marginBottom: "1.5rem", fontSize: "0.9rem" }}>
19	        Tracked thinkers and corpora in the Noosphere store (distinct from founders). Verdicts and
20	        positions are always scoped to ingested artifacts — not implied to be a complete historical
21	        view. Set <code style={{ color: "var(--gold-dim)" }}>NOOSPHERE_DATABASE_URL</code> to the same
22	        SQLite file the CLI uses.
23	      </p>
24	      {skipped ? (
25	        <p style={{ color: "var(--parchment-dim)", fontSize: "0.85rem" }}>
26	          {message || "Voices bridge skipped."}
27	        </p>
28	      ) : rows.length === 0 ? (
29	        <p style={{ color: "var(--parchment-dim)" }}>
30	          No Voice profiles yet. Run{" "}
31	          <code style={{ color: "var(--gold-dim)" }}>
32	            python -m noosphere ingest-voice --name &quot;…&quot; path/to/corpus.md
33	          </code>{" "}
34	          or{" "}
35	          <code style={{ color: "var(--gold-dim)" }}>
36	            python -m noosphere ingest --as-voice --voice-name &quot;…&quot; path/to/corpus.txt
37	          </code>
38	          .
39	        </p>
40	      ) : (
41	        <ul style={{ listStyle: "none", padding: 0, margin: 0, display: "flex", flexDirection: "column", gap: "1rem" }}>
42	          {rows.map((v) => (
43	            <li
44	              key={v.id}
45	              style={{
46	                border: "1px solid var(--border)",
47	                borderRadius: "6px",
48	                padding: "1rem 1.25rem",
49	                background: "var(--stone)",
50	              }}
51	            >
52	              <Link
53	                href={`/voices/${v.id}`}
54	                style={{
55	                  fontFamily: "'Cinzel', serif",
56	                  color: "var(--gold)",
57	                  textDecoration: "none",
58	                  letterSpacing: "0.06em",
59	                  fontSize: "0.95rem",
60	                }}
61	              >
62	                {v.canonicalName}
63	              </Link>
64	              <div style={{ marginTop: "0.5rem", fontSize: "0.8rem", color: "var(--parchment-dim)" }}>
65	                Citations from firm artifacts: <strong style={{ color: "var(--parchment)" }}>{v.citationCount}</strong>
66	                {" · "}
67	                Ingested claims: <strong style={{ color: "var(--parchment)" }}>{v.claimCount}</strong>
68	                {" · "}
69	                Corpus artifacts: <strong style={{ color: "var(--parchment)" }}>{v.corpusCount}</strong>
70	              </div>
71	              {v.traditions.length > 0 && (
72	                <div style={{ marginTop: "0.35rem", fontSize: "0.75rem", color: "var(--gold-dim)" }}>
73	                  Traditions: {v.traditions.join(", ")}
74	                </div>
75	              )}
76	            </li>
77	          ))}
78	        </ul>
79	      )}
80	    </main>
81	  );
82	}
