1	@import url('https://fonts.googleapis.com/css2?family=EB+Garamond:ital,wght@0,400;0,500;0,600;1,400;1,500&family=Cinzel:wght@400;500;600&family=Inter:wght@300;400;500&display=swap');
2	@import "tailwindcss";
3	
4	/* ── Theseus Design Tokens (from Codex) ──────────────────────────────────── */
5	
6	:root {
7	  --stone: #0d0c0b;
8	  --stone-light: #1a1814;
9	  --stone-mid: #252218;
10	  --parchment: #e8dcc8;
11	  --parchment-dim: #b8aa90;
12	  --gold: #c9a84c;
13	  --gold-dim: #8a6e2a;
14	  --ember: #8b3a2a;
15	  --border: #2e2a1e;
16	  --success: #4a7a3a;
17	  --info: #3a5a7a;
18	}
19	
20	[data-theme="light"] {
21	  --stone: #f2e8d9;
22	  --stone-light: #ede0cc;
23	  --stone-mid: #e4d4ba;
24	  --parchment: #2a2318;
25	  --parchment-dim: #5a4e3a;
26	  --gold: #7a5218;
27	  --gold-dim: #9a6c28;
28	  --ember: #8b3a2a;
29	  --border: #cbbfa8;
30	  --success: #3a6a2a;
31	  --info: #2a4a6a;
32	}
33	
34	html { transition: background 0.25s, color 0.25s; }
35	
36	@theme inline {
37	  --color-background: var(--stone);
38	  --color-foreground: var(--parchment);
39	}
40	
41	* { box-sizing: border-box; }
42	
43	html, html[data-theme] {
44	  background: var(--stone);
45	  color: var(--parchment);
46	}
47	
48	body {
49	  background: var(--stone);
50	  color: var(--parchment);
51	  font-family: 'EB Garamond', Georgia, serif;
52	  font-size: 17px;
53	  line-height: 1.7;
54	  min-height: 100vh;
55	}
56	
57	h1, h2, h3, h4 {
58	  font-family: 'Cinzel', 'Palatino Linotype', serif;
59	  font-weight: 500;
60	  letter-spacing: 0.05em;
61	}
62	
63	/* ── Scrollbar ───────────────────────────────────────────────────────────── */
64	::-webkit-scrollbar { width: 6px; }
65	::-webkit-scrollbar-track { background: var(--stone); }
66	::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }
67	::selection { background: var(--gold-dim); color: var(--parchment); }
68	
69	/* ── Form elements ───────────────────────────────────────────────────────── */
70	input, textarea, select {
71	  background: var(--stone-light);
72	  border: 1px solid var(--border);
73	  color: var(--parchment);
74	  font-family: 'EB Garamond', Georgia, serif;
75	  font-size: 1rem;
76	  padding: 0.6rem 0.9rem;
77	  border-radius: 2px;
78	  outline: none;
79	  transition: border-color 0.2s;
80	  width: 100%;
81	}
82	
83	input:focus, textarea:focus, select:focus {
84	  border-color: var(--gold-dim);
85	}
86	
87	input::placeholder, textarea::placeholder {
88	  color: var(--parchment-dim);
89	  opacity: 0.5;
90	}
91	
92	/* ── Buttons ─────────────────────────────────────────────────────────────── */
93	.btn {
94	  font-family: 'Cinzel', serif;
95	  font-size: 0.75rem;
96	  letter-spacing: 0.12em;
97	  text-transform: uppercase;
98	  padding: 0.6rem 1.4rem;
99	  border: 1px solid var(--gold-dim);
100	  background: transparent;
101	  color: var(--gold);
102	  cursor: pointer;
103	  transition: all 0.2s;
104	  border-radius: 1px;
