106	
107	.btn:hover {
108	  background: var(--gold-dim);
109	  color: var(--stone);
110	}
111	
112	.btn-solid {
113	  background: var(--gold-dim);
114	  color: var(--stone);
115	  border-color: var(--gold-dim);
116	}
117	
118	.btn-solid:hover {
119	  background: var(--gold);
120	  border-color: var(--gold);
121	}
122	
123	/* ── Cards ───────────────────────────────────────────────────────────────── */
124	.portal-card {
125	  background: var(--stone-light);
126	  border: 1px solid var(--border);
127	  border-radius: 2px;
128	  padding: 1.5rem;
129	  transition: border-color 0.2s;
