131	
132	.portal-card:hover {
133	  border-color: var(--gold-dim);
134	}
135	
136	/* ── Upload zone ─────────────────────────────────────────────────────────── */
137	.upload-zone {
138	  border: 2px dashed var(--border);
139	  border-radius: 2px;
140	  padding: 3rem 2rem;
141	  text-align: center;
142	  transition: all 0.2s;
143	  cursor: pointer;
144	}
145	
146	.upload-zone:hover, .upload-zone.dragover {
147	  border-color: var(--gold-dim);
148	  background: var(--stone-light);
149	}
150	
151	/* ── Status badges ───────────────────────────────────────────────────────── */
152	.badge {
153	  font-family: 'Inter', sans-serif;
154	  font-size: 0.65rem;
155	  letter-spacing: 0.08em;
156	  text-transform: uppercase;
157	  padding: 0.2rem 0.6rem;
158	  border-radius: 1px;
159	  display: inline-block;
160	}
161	
162	.badge-pending { background: var(--stone-mid); color: var(--parchment-dim); }
163	.badge-processing { background: var(--info); color: var(--parchment); }
164	.badge-ingested { background: var(--success); color: var(--parchment); }
165	.badge-failed { background: var(--ember); color: var(--parchment); }
166	
167	/* ── Stat card ───────────────────────────────────────────────────────────── */
168	.stat-card {
169	  background: var(--stone-light);
170	  border: 1px solid var(--border);
171	  border-radius: 2px;
172	  padding: 1.2rem;
173	  text-align: center;
174	}
175	
176	.stat-value {
177	  font-family: 'Cinzel', serif;
178	  font-size: 2rem;
179	  color: var(--gold);
180	  font-weight: 500;
181	}
182	
183	.stat-label {
184	  font-family: 'Inter', sans-serif;
185	  font-size: 0.65rem;
186	  letter-spacing: 0.12em;
187	  text-transform: uppercase;
188	  color: var(--parchment-dim);
189	  margin-top: 0.3rem;
190	}
191	
192	/* ── Ornament ────────────────────────────────────────────────────────────── */
193	.ornament::before {
194	  content: '— ✦ —';
195	  color: var(--gold-dim);
196	  font-family: 'Cinzel', serif;
197	  font-size: 0.75rem;
198	  letter-spacing: 0.3em;
199	}
200	
201	/* ── Animation ───────────────────────────────────────────────────────────── */
202	@keyframes fadeUp {
203	  from { opacity: 0; transform: translateY(8px); }
204	  to { opacity: 1; transform: translateY(0); }
205	}
206	
207	.fade-up { animation: fadeUp 0.4s ease forwards; }
