1	import { NextResponse } from "next/server";
2	import bcrypt from "bcryptjs";
3	import { db } from "@/lib/db";
4	import { createSession } from "@/lib/auth";
5	import { checkLoginRateLimit, resetLoginRateLimit } from "@/lib/rateLimit";
6	
7	function clientIp(req: Request): string {
8	  const xf = req.headers.get("x-forwarded-for");
9	  if (xf) return xf.split(",")[0]!.trim();
10	  return req.headers.get("x-real-ip") || "unknown";
11	}
12	
13	export async function POST(req: Request) {
14	  try {
15	    const { email, password, organizationSlug } = (await req.json()) as {
16	      email?: string;
17	      password?: string;
18	      organizationSlug?: string;
19	    };
20	    const ip = clientIp(req);
21	    const rateKey = `${ip}::${(email || "").toLowerCase()}`;
22	
23	    if (!email || !password) {
24	      return NextResponse.json({ error: "Email and password required" }, { status: 400 });
25	    }
26	
27	    const slug =
28	      (organizationSlug && String(organizationSlug).trim()) ||
29	      process.env.DEFAULT_ORGANIZATION_SLUG ||
30	      "theseus-local";
31	
32	    const org = await db.organization.findUnique({ where: { slug } });
33	    if (!org) {
34	      return NextResponse.json({ error: "Unknown organization" }, { status: 400 });
35	    }
36	
37	    const founder = await db.founder.findFirst({
38	      where: { organizationId: org.id, email },
39	    });
40	    const valid = founder ? await bcrypt.compare(password, founder.passwordHash) : false;
41	
42	    if (!founder || !valid) {
43	      const limited = checkLoginRateLimit(rateKey);
44	      if (!limited.ok) {
45	        return NextResponse.json(
46	          { error: `Too many attempts. Try again in ${limited.retryAfterSec}s.` },
47	          {
48	            status: 429,
49	            headers: { "Retry-After": String(limited.retryAfterSec) },
50	          },
51	        );
52	      }
53	      return NextResponse.json({ error: "Invalid credentials" }, { status: 401 });
54	    }
55	
56	    resetLoginRateLimit(rateKey);
57	
58	    await createSession(founder.id);
59	
60	    await db.auditEvent.create({
61	      data: {
