1	import { createHmac, randomBytes, timingSafeEqual } from "crypto";
2	import { cookies } from "next/headers";
3	import { db } from "./db";
4	
5	/** Exported for documentation; middleware uses the same literal (Edge-safe, no Node crypto). */
6	export const THESEUS_SESSION_COOKIE = "theseus_session";
7	const COOKIE_NAME = THESEUS_SESSION_COOKIE;
8	
9	function getSessionSecret(): string {
10	  const s = process.env.SESSION_SECRET;
11	  if (!s || s === "change-me-to-a-random-hex-string") {
12	    if (process.env.NODE_ENV === "production") {
13	      throw new Error("SESSION_SECRET must be set in production");
14	    }
15	    return "dev-insecure-session-secret-do-not-use";
16	  }
17	  return s;
18	}
19	
20	/** Base64url encode */
21	function b64url(buf: Buffer): string {
22	  return buf
23	    .toString("base64")
24	    .replace(/\+/g, "-")
25	    .replace(/\//g, "_")
26	    .replace(/=+$/, "");
27	}
28	
29	function signPayload(payloadJson: string): string {
30	  const secret = getSessionSecret();
31	  const sig = createHmac("sha256", secret).update(payloadJson).digest();
32	  return `${b64url(Buffer.from(payloadJson, "utf8"))}.${b64url(sig)}`;
33	}
34	
35	/**
36	 * Verify signed session cookie (Edge-safe string compare; crypto in Node).
37	 * Returns `{ token, exp }` from payload or null.
38	 */
39	export function verifySessionCookieValue(raw: string | undefined): {
40	  token: string;
41	  exp: number;
42	} | null {
43	  if (!raw || !raw.includes(".")) return null;
44	  const lastDot = raw.lastIndexOf(".");
45	  const payloadB64 = raw.slice(0, lastDot);
46	  const sigB64 = raw.slice(lastDot + 1);
47	  try {
48	    const payloadJson = Buffer.from(
49	      payloadB64.replace(/-/g, "+").replace(/_/g, "/"),
50	      "base64",
51	    ).toString("utf8");
52	    const expectedSig = createHmac("sha256", getSessionSecret())
53	      .update(payloadJson)
54	      .digest();
55	    const gotSig = Buffer.from(
56	      sigB64.replace(/-/g, "+").replace(/_/g, "/"),
57	      "base64",
58	    );
59	    if (gotSig.length !== expectedSig.length || !timingSafeEqual(gotSig, expectedSig)) {
60	      return null;
61	    }
62	    const body = JSON.parse(payloadJson) as { t: string; e: number };
63	    if (!body.t || typeof body.e !== "number") return null;
64	    return { token: body.t, exp: body.e };
65	  } catch {
66	    return null;
67	  }
68	}
69	
70	/**
71	 * Get the currently authenticated founder from the signed HTTP-only session cookie.
72	 */
73	export async function getFounder() {
74	  const cookieStore = await cookies();
75	  const raw = cookieStore.get(COOKIE_NAME)?.value;
76	  const v = verifySessionCookieValue(raw);
77	  if (!v) return null;
78	  if (Date.now() > v.exp) return null;
79	
80	  const session = await db.session.findUnique({
81	    where: { token: v.token },
82	    include: { founder: { include: { organization: true } } },
83	  });
84	
85	  if (!session || session.expiresAt < new Date()) {
86	    return null;
87	  }
88	
89	  return session.founder;
90	}
91	
92	/**
93	 * Create a DB session and set signed HTTP-only cookie.
94	 */
95	export async function createSession(founderId: string) {
96	  const token = randomBytes(32).toString("hex");
97	  const expiresAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000);
98	
99	  const f = await db.founder.findUnique({
100	    where: { id: founderId },
101	    select: { organizationId: true },
102	  });
103	  if (!f) {
104	    throw new Error("createSession: founder not found");
105	  }
106	
107	  await db.session.create({
108	    data: {
109	      organizationId: f.organizationId,
110	      founderId,
111	      token,
112	      expiresAt,
113	    },
114	  });
115	
116	  const payload = JSON.stringify({ t: token, e: expiresAt.getTime() });
117	  const signed = signPayload(payload);
118	
119	  const cookieStore = await cookies();
120	  cookieStore.set(COOKIE_NAME, signed, {
121	    httpOnly: true,
122	    secure: process.env.NODE_ENV === "production",
123	    sameSite: "lax",
124	    expires: expiresAt,
125	    path: "/",
126	  });
127	
128	  return token;
129	}
130	
131	export async function destroySession() {
132	  const cookieStore = await cookies();
133	  const raw = cookieStore.get(COOKIE_NAME)?.value;
134	  const v = verifySessionCookieValue(raw);
135	  if (v?.token) {
136	    await db.session.deleteMany({ where: { token: v.token } });
137	  }
138	  cookieStore.delete(COOKIE_NAME);
139	}
140	
141	export { COOKIE_NAME };
